SELECT symbol, company_name
FROM stocks
WHERE market_cap = (
  SELECT MAX(market_cap)
  FROM stocks
);

SELECT COUNT(DISTINCT user_id) 
FROM access_logs 
WHERE access_date >= DATE('now', '-30 days');

SELECT close_price
FROM daily_prices
WHERE date = (SELECT MAX(date) FROM daily_prices);

SELECT MAX(date) AS final_trading_day, SUM(turnover) AS total_turnover
FROM daily_prices
WHERE date = (SELECT MAX(date) FROM daily_prices);

SELECT DISTINCT stock_id, company_name
FROM stocks
ORDER BY company_name;

SELECT MAX(close_price) AS highest_price
FROM daily_prices
WHERE date > DATE('now', '-30 days');

SELECT AVG(DISTINCT close_price) AS average_closing_price
FROM daily_prices
WHERE close_price > (
    SELECT AVG(close_price) 
    FROM daily_prices
);
